  async function applyAnimator(plan, onStatus) {
    const critiques = plan.__motionCritiques;
    if (!critiques || critiques.length === 0) {
      console.log("[Animator] No motion critiques available \u2014 skipping (requires Motion Director)");
      return;
    }
    const targets = critiques.filter((c) => c.craftScore < 9 && Array.isArray(c.violations) && c.violations.length > 0).map((c) => ({ critique: c, scene: plan.scenes[c.sceneIndex] })).filter(({ scene }) => scene && !!scene.customCode);
    if (targets.length === 0) {
      console.log("[Animator] No scenes need refinement (all critiques clean or no customCode)");
      return;
    }
    onStatus?.(`Animator refining ${targets.length} scene(s)...`);
    console.log(
      `[Animator] Refining ${targets.length} scene(s):`,
      targets.map((t) => `#${t.critique.sceneIndex} (${t.critique.craftScore}/10, ${t.critique.violations.length}v)`).join(", ")
    );
    const results = await Promise.allSettled(
      targets.map(
        ({ critique, scene }) => refineSceneCode(scene, critique, plan)
      )
    );
    let appliedCount = 0;
    let skippedCount = 0;
    for (let i = 0; i < results.length; i++) {
      const result = results[i];
      const target = targets[i];
      if (result.status === "rejected") {
        console.warn(
          `[Animator] Scene #${target.critique.sceneIndex} refinement failed:`,
          result.reason?.message || result.reason
        );
        skippedCount++;
        continue;
      }
      const refined = result.value;
      if (!refined) {
        skippedCount++;
        continue;
      }
      try {
        const wrapped = `function VideoComposition({ screenshots }) {
${refined}
}`;
        compileCode(wrapped);
        target.scene.customCode = refined;
        appliedCount++;
        console.log(
          `[Animator] \u2713 Scene #${target.critique.sceneIndex} refined (${refined.length} chars)`
        );
      } catch (err) {
        console.warn(
          `[Animator] Scene #${target.critique.sceneIndex} refined code failed to compile \u2014 keeping original:`,
          err?.message?.slice(0, 120)
        );
        skippedCount++;
      }
    }
    console.log(
      `[Animator] \u2713 Applied ${appliedCount} refinement(s), skipped ${skippedCount}`
    );
  }
  async function iterativelyRefineScenes(plan, onStatus, options) {
    const maxPasses = options?.maxPasses ?? 3;
    const targetScore = options?.targetScore ?? 8;
    const refinedHistory = /* @__PURE__ */ new Set();
    let pass = 0;
    while (pass < maxPasses) {
      pass++;
      onStatus?.(`Polish pass ${pass}/${maxPasses}: critiquing scenes...`);
      try {
        await applyMotionDirector(plan, onStatus);
      } catch (err) {
        console.warn(`[IterativeRefine] Pass ${pass} critique failed:`, err);
        break;
      }
      const critiques = plan.__motionCritiques;
      if (!critiques || critiques.length === 0) {
        console.log(`[IterativeRefine] No critiques produced \u2014 stopping after pass ${pass}`);
        break;
      }
      const lowScoring = critiques.filter(
        (c) => c.craftScore < targetScore && Array.isArray(c.violations) && c.violations.length > 0
      );
      if (lowScoring.length === 0) {
        onStatus?.(`\u2713 All scenes refined to ${targetScore}+/10 after ${pass} pass${pass > 1 ? "es" : ""}`);
        console.log(`[IterativeRefine] \u2713 All scenes meet target ${targetScore} after ${pass} pass(es)`);
        break;
      }
      const sceneList = lowScoring.map((c) => `#${c.sceneIndex}(${c.craftScore})`).join(", ");
      onStatus?.(`Polish pass ${pass}: refining ${lowScoring.length} scene(s) \u2014 ${sceneList}`);
      console.log(`[IterativeRefine] Pass ${pass}: refining ${lowScoring.length} scenes: ${sceneList}`);
      try {
        await applyAnimator(plan, onStatus);
      } catch (err) {
        console.warn(`[IterativeRefine] Pass ${pass} refinement failed:`, err);
        break;
      }
      for (const c of lowScoring) refinedHistory.add(c.sceneIndex);
    }
    const finalCritiques = plan.__motionCritiques;
    const finalScores = finalCritiques?.map((c) => c.craftScore) ?? [];
    const finalAvg = finalScores.length ? finalScores.reduce((a, b) => a + b, 0) / finalScores.length : 0;
    console.log(
      `[IterativeRefine] \u2713 Done \u2014 ${pass} pass(es), ${refinedHistory.size} scenes refined, final avg score ${finalAvg.toFixed(1)}/10`
    );
    return { passesRun: pass, scenesRefined: refinedHistory.size, finalAvgScore: finalAvg };
  }
