  async function writeCustomMusicPromptFromBrief(plan, userBrief) {
    const brief = (userBrief || "").trim();
    if (!brief) return null;
    const needsCustom = /\b(?:techno|rave|acid house|jungle|drum.?and.?bass|dnb|house|trance|hardcore|gabber|garage|breakbeat|phonk|dubstep|jazz|bebop|classical|symphony|hip.?hop|rap|trap|boom.?bap|reggae|ska|dub|afrobeat|samba|bossa|cumbia|flamenco|metal|punk|indie rock|post.?rock|shoegaze|ambient drone|industrial|noise|fatboy slim|daft punk|aphex|prodigy|chemical brothers|underworld|moby|kraftwerk|tangerine dream|vangelis|bjork|nine inch nails|massive attack|portishead|boards of canada|burial|skrillex|deadmau5|tiesto|carl cox|jeff mills)\b/i.test(
      brief
    );
    if (!needsCustom) return null;
    const aesthetic = plan.__aesthetic;
    const title = plan.title || "";
    const system = [
      "You are a Music Director for a motion-graphics video. Write a detailed",
      "instrumental-music generation prompt.",
      "",
      "CRITICAL CONTENT POLICY:",
      "- NEVER name real artists, bands, DJs, producers, labels, songs, or albums.",
      "  Music-generation APIs (ElevenLabs, MiniMax) reject prompts that reference",
      "  real people or copyrighted titles. A prompt with 'Fatboy Slim', 'Daft Punk',",
      "  'Ninja Tune', 'Praise You', etc. will be blocked outright.",
      "- Instead, describe the SOUND: sub-genre, production era, tempo, instruments,",
      "  sonic signatures, mood. The model can reproduce a style perfectly from",
      "  those details \u2014 it does not need a name to copy.",
      "",
      "Your prompt must be concrete enough for the model to produce the RIGHT",
      "genre \u2014 not a generic approximation. Include:",
      "- Specific sub-genre + era (e.g. 'late-90s big beat', '90s UK acid house',",
      "  'early-2000s Berlin techno', 'mid-2010s future garage')",
      "- BPM (e.g. 130 BPM, 174 BPM)",
      "- Key instruments / production signatures (e.g. TB-303 acid bass squelch,",
      "  909 kick, breakbeat samples, vinyl crackle, hoover synth stabs, 808 sub,",
      "  filtered disco loops, reversed cymbals, cowbell)",
      "- Mood/energy descriptors (euphoric, crowd-hype, gritty, analog, cinematic)",
      "- Structure notes (builds in first third, drop at midpoint, anthemic climax)",
      "- Always add 'Instrumental' unless lyrics were requested",
      "- End with 'The track should be exactly N seconds long.'",
      "",
      "EXAMPLE (for a brief that referenced big-beat / Fatboy-Slim-era music):",
      `"Late-90s big beat instrumental. 130 BPM. Chunky breakbeat drums with heavy swing, driving funky bassline, layered vinyl-crackle vocal chops (soul and rock samples chopped into rhythmic stabs, no intelligible lyrics), punchy kick and snare, playful uplifting mood, one repetitive earworm hook that loops and builds, dynamic tension-and-release with filter sweeps into drops, gritty analog saturation, crowd-hype festival-dancefloor energy. Instrumental. The track should be exactly 20 seconds long."`,
      "",
      "Respond with ONLY the prompt text \u2014 no preamble, no JSON, no quotes around it."
    ].join("\n");
    const user = [
      `Video title: ${title || "(untitled)"}`,
      aesthetic ? `Aesthetic: ${aesthetic.name} \u2014 ${aesthetic.description}` : "",
      `Brief: ${brief}`,
      "",
      "Write the MiniMax music prompt for this video."
    ].filter(Boolean).join("\n");
    try {
      const result = await window.electronAPI?.aiAnalyze(user, system);
      if (!result?.success || !result.text) return null;
      const text = result.text.trim().replace(/^["']|["']$/g, "");
      return text.length > 20 ? text : null;
    } catch {
      return null;
    }
  }
