  var DEFAULT_POLISH_BACKGROUNDS = [
    "mesh-apple-dark",
    "animated-midnight",
    "animated-ocean-wave",
    "particle-bokeh-cool"
  ];
  function polishSceneProject(project) {
    const styleId = project.styleId;
    const style = styleId ? getDesignStyle(styleId) : null;
    const polishBackgrounds = style && style.backgroundIds.length > 0 ? style.backgroundIds : DEFAULT_POLISH_BACKGROUNDS;
    const fallbackBg = style?.fallbackBackground ?? "animated-midnight";
    const preview = {
      backgroundsChanged: 0,
      transitionsAdded: 0,
      animationsEnhanced: 0,
      durationsAdjusted: 0,
      totalScenes: project.scenes.length
    };
    const mainBg = polishBackgrounds[Math.floor(Math.random() * polishBackgrounds.length)];
    const lastBg = polishBackgrounds.find((b) => b !== mainBg) ?? fallbackBg;
    const polishedScenes = project.scenes.map((scene, sceneIdx) => {
      const isFirst = sceneIdx === 0;
      const isLast = sceneIdx === project.scenes.length - 1;
      let background = scene.background;
      if (background === "#09090b" || background === "#000000" || background === "#0f172a") {
        background = isLast ? lastBg : mainBg;
        preview.backgroundsChanged++;
      }
      let transition = scene.transition;
      if (isFirst) {
        transition = { type: "none", durationMs: 0 };
      } else if (isLast) {
        if (transition.type === "none") {
          transition = { type: "zoom", durationMs: 500 };
          preview.transitionsAdded++;
        }
      } else {
        if (transition.type === "none") {
          transition = { type: "fade", durationMs: 400 };
          preview.transitionsAdded++;
        }
      }
      let durationMs = scene.durationMs;
      const textLayers = scene.layers.filter((l) => l.type === "text");
      const totalTextLength = textLayers.reduce((sum, l) => {
        const content = l.content;
        return sum + (content.text?.length ?? 0);
      }, 0);
      if (totalTextLength > 100 && durationMs < 5e3) {
        durationMs = 5e3;
        preview.durationsAdjusted++;
      } else if (totalTextLength > 50 && durationMs < 4e3) {
        durationMs = 4e3;
        preview.durationsAdjusted++;
      } else if (totalTextLength === 0 && durationMs > 3500) {
        durationMs = 3e3;
        preview.durationsAdjusted++;
      }
      const layers = scene.layers.map((layer, layerIdx) => {
        const enhanced = { ...layer };
        if (layer.type === "image") {
          if (layer.entrance.type === "fade" || layer.entrance.type === "none") {
            enhanced.entrance = {
              type: "ken-burns",
              durationMs,
              // Ken-burns runs the whole scene
              easing: "ease-out",
              delay: 0
            };
            preview.animationsEnhanced++;
          }
        }
        if (layer.type === "text") {
          const isTitle = layer.content.fontSize ? layer.content.fontSize >= 36 : false;
          const titleAnim = style?.defaultTitleEntrance ?? {
            type: "blur-in",
            durationMs: 500,
            delay: 0
          };
          const subtitleAnim = style?.defaultSubtitleEntrance ?? {
            type: "slide-up",
            durationMs: 400,
            delay: 300
          };
          if (isTitle) {
            if (layer.entrance.type === "fade" || layer.entrance.type === "none") {
              enhanced.entrance = {
                type: titleAnim.type,
                durationMs: titleAnim.durationMs,
                easing: "ease-out",
                delay: isFirst ? titleAnim.delay + 100 : titleAnim.delay
              };
              preview.animationsEnhanced++;
            }
          } else {
            if (layer.entrance.type === "fade" || layer.entrance.type === "none") {
              enhanced.entrance = {
                type: subtitleAnim.type,
                durationMs: subtitleAnim.durationMs,
                easing: "ease-out",
                delay: subtitleAnim.delay + layerIdx * 150
              };
              preview.animationsEnhanced++;
            }
          }
          if (layer.exit.type === "none" && !isLast) {
            enhanced.exit = {
              type: "fade",
              durationMs: 300,
              easing: "ease-in",
              delay: 0
            };
          }
        }
        enhanced.endMs = durationMs;
        return enhanced;
      });
      return {
        ...scene,
        background,
        transition,
        durationMs,
        layers
      };
    });
    return {
      project: { ...project, scenes: polishedScenes },
      preview
    };
  }
  var AI_POLISH_PROMPT = `You are a motion design expert. Analyze this screenshot from a product demo video and suggest enhancements.

Respond with JSON only:
{
  "focusArea": "top-left" | "top-right" | "center" | "bottom-left" | "bottom-right",
  "imageAnimation": "ken-burns" | "zoom-in" | "fade",
  "textAnimation": "blur-in" | "slide-up" | "fade",
  "suggestedDurationMs": 3000-6000,
  "background": "mesh-apple-dark" | "animated-midnight" | "animated-ocean-wave" | "particle-bokeh-cool",
  "reasoning": "brief explanation"
}

Rules:
- focusArea: where the most important content is (hero text, dashboard, key feature)
- imageAnimation: ken-burns for screenshots with lots of content, zoom-in for focused elements, fade for simple pages
- textAnimation: blur-in for titles/headers, slide-up for descriptions
- suggestedDurationMs: longer for text-heavy pages (5000), shorter for visual pages (3000)
- background: pick one that complements the screenshot's color palette`;
  async function aiPolishSceneProject(project, onProgress) {
    const styleId = project.styleId;
    const style = styleId ? getDesignStyle(styleId) : null;
    const { project: basePolished, preview } = polishSceneProject(project);
    const scenes = [...basePolished.scenes];
    let aiEnhanced = 0;
    for (let i = 0; i < scenes.length; i++) {
      const scene = scenes[i];
      onProgress?.(i, scenes.length);
      const imageLayer = scene.layers.find((l) => l.type === "image");
      if (!imageLayer || !imageLayer.content.src) continue;
      const src = imageLayer.content.src;
      if (!src.startsWith("data:image")) continue;
      try {
        const base64 = src.replace(/^data:image\/\w+;base64,/, "");
        const result = await window.electronAPI?.aiAnalyzeImage(
          "Analyze this demo screenshot for motion design enhancements.",
          base64,
          AI_POLISH_PROMPT
        );
        if (!result?.success || !result.text) continue;
        let json = result.text.trim();
        const match = json.match(/\{[\s\S]*\}/);
        if (match) json = match[0];
        const suggestion = JSON.parse(json);
        const validAnimations = [
          "ken-burns",
          "zoom-in",
          "fade",
          "blur-in",
          "slide-up"
        ];
        if (validAnimations.includes(suggestion.imageAnimation)) {
          const imgIdx = scene.layers.findIndex((l) => l.type === "image");
          if (imgIdx >= 0) {
            scenes[i] = {
              ...scenes[i],
              layers: scenes[i].layers.map(
                (l, li) => li === imgIdx ? {
                  ...l,
                  entrance: {
                    ...l.entrance,
                    type: suggestion.imageAnimation
                  }
                } : l
              )
            };
          }
        }
        if (validAnimations.includes(suggestion.textAnimation)) {
          scenes[i] = {
            ...scenes[i],
            layers: scenes[i].layers.map(
              (l) => l.type === "text" ? {
                ...l,
                entrance: {
                  ...l.entrance,
                  type: suggestion.textAnimation
                }
              } : l
            )
          };
        }
        if (suggestion.suggestedDurationMs >= 2e3 && suggestion.suggestedDurationMs <= 8e3) {
          scenes[i] = {
            ...scenes[i],
            durationMs: suggestion.suggestedDurationMs,
            layers: scenes[i].layers.map((l) => ({
              ...l,
              endMs: suggestion.suggestedDurationMs
            }))
          };
        }
        const validBgs = style && style.backgroundIds.length > 0 ? style.backgroundIds : DEFAULT_POLISH_BACKGROUNDS;
        if (validBgs.includes(suggestion.background)) {
          scenes[i] = { ...scenes[i], background: suggestion.background };
        }
        aiEnhanced++;
      } catch {
        continue;
      }
    }
    preview.animationsEnhanced += aiEnhanced;
    return {
      project: { ...basePolished, scenes },
      preview
    };
  }

